"use strict";(globalThis.webpackChunkwebsite=globalThis.webpackChunkwebsite||[]).push([[8845],{4846:(e,t,i)=>{i.r(t),i.d(t,{assets:()=>d,contentTitle:()=>r,default:()=>c,frontMatter:()=>o,metadata:()=>n,toc:()=>l});const n=JSON.parse('{"id":"training/part2-hands-on/pcap-deep-dive-the-on-premises-identity-portal","title":"33. PCAP Deep Dive: The On-Premises Identity Portal","description":"33.1 Positioning: The Sovereign CAS","source":"@site/docs/training/part2-hands-on/33-pcap-deep-dive-the-on-premises-identity-portal.md","sourceDirName":"training/part2-hands-on","slug":"/training/part2-hands-on/pcap-deep-dive-the-on-premises-identity-portal","permalink":"/rsapsdocumentation/docs/training/part2-hands-on/pcap-deep-dive-the-on-premises-identity-portal","draft":false,"unlisted":false,"tags":[],"version":"current","sidebarPosition":33,"frontMatter":{"title":"33. PCAP Deep Dive: The On-Premises Identity Portal","sidebar_position":33},"sidebar":"docsSidebar","previous":{"title":"32. Virtual Token Service (VTS) \u2014 End-to-End Build","permalink":"/rsapsdocumentation/docs/training/part2-hands-on/virtual-token-service-vts--end-to-end-build"},"next":{"title":"34. Branding and Customization (Part 2)","permalink":"/rsapsdocumentation/docs/training/part2-hands-on/branding-and-customization-part-2"}}');var a=i(4848),s=i(8453);const o={title:"33. PCAP Deep Dive: The On-Premises Identity Portal",sidebar_position:33},r="33. PCAP Deep Dive: The On-Premises Identity Portal",d={},l=[{value:"33.1 Positioning: The Sovereign CAS",id:"331-positioning-the-sovereign-cas",level:2},{value:"33.2 Capabilities and Configuration Surface",id:"332-capabilities-and-configuration-surface",level:2},{value:"33.3 SAML Application Integration (Demonstrated)",id:"333-saml-application-integration-demonstrated",level:2},{value:"33.4 The Extended Live Debug \u2014 and What It Taught",id:"334-the-extended-live-debug--and-what-it-taught",level:2},{value:"33.5 Patching and Rollback via WAR Files (Bonus Module)",id:"335-patching-and-rollback-via-war-files-bonus-module",level:2},{value:"33.6 Compliance Sidebar: SOC Reports",id:"336-compliance-sidebar-soc-reports",level:2}];function h(e){const t={em:"em",h1:"h1",h2:"h2",header:"header",li:"li",ol:"ol",p:"p",ul:"ul",...(0,s.R)(),...e.components};return(0,a.jsxs)(a.Fragment,{children:[(0,a.jsx)(t.header,{children:(0,a.jsx)(t.h1,{id:"33-pcap-deep-dive-the-on-premises-identity-portal",children:"33. PCAP Deep Dive: The On-Premises Identity Portal"})}),"\n",(0,a.jsx)(t.h2,{id:"331-positioning-the-sovereign-cas",children:"33.1 Positioning: The Sovereign CAS"}),"\n",(0,a.jsxs)(t.p,{children:["PCAP received its full treatment as the answer to a specific gap: on-prem Authentication Manager does not speak SAML or OIDC \u2014 only its native SecurID protocols, REST MFA, and RADIUS. Customers who want MFA-protected single sign-on but cannot use the Cloud Authentication Service therefore have no core-product path. PCAP is that path: 'pretty much similar to what CAS is doing' as a user portal and identity provider, run entirely on-premises against AM as the source of truth. The trainer drew the strategic parallel explicitly: PCAP is functionally ",(0,a.jsx)(t.em,{children:"'your sovereign CAS deployment'"})," \u2014 the same shape as the sovereign offering engineering is building. Routing guidance was equally explicit: enterprise and strategic customers should be pushed to cloud CAS ('you already have all these capabilities \u2014 just integrate any SAML 2.0 or OIDC application to cloud'); PCAP is for the environments that cannot get there \u2014 heavily federal and DoD, including CAC smart-card front ends. Hillis has deployed PCAP more than any other consultant and is the delivery escalation."]}),"\n",(0,a.jsx)(t.h2,{id:"332-capabilities-and-configuration-surface",children:"33.2 Capabilities and Configuration Surface"}),"\n",(0,a.jsxs)(t.ul,{children:["\n",(0,a.jsx)(t.li,{children:"User portal: authenticated users see the applications they are entitled to \u2014 SAML 2.0 integrations, OIDC integrations, and bookmarks \u2014 driven by group membership or user attributes, configured via XML."}),"\n",(0,a.jsx)(t.li,{children:"Front-end authentication: SAML, OIDC, token, certificate (smart card/CAC), and password \u2014 with chaining supported across methods. No automation exists yet for portal configuration."}),"\n",(0,a.jsx)(t.li,{children:"IdP and SP duality: PCAP can act as an identity provider (asserting into downstream apps like Salesforce, ServiceNow, SailPoint, Office 365 \u2014 anything SAML 2.0) and as a service provider (accepting assertions from an upstream IdP such as Okta), simultaneously."}),"\n",(0,a.jsx)(t.li,{children:"Two configuration files: pcapconfig.xml (in configs/AMS) governs which front-end authentication methods appear \u2014 the out-of-box file shows everything, and consultants comment out what the customer doesn't want (demonstrated live: reducing the login page to token-only, with a lesson en route: the change didn't take until the file was actually saved). am8config.xml holds the central authentication section where applications are integrated \u2014 the IdP configuration page in file form."}),"\n"]}),"\n",(0,a.jsx)(t.h2,{id:"333-saml-application-integration-demonstrated",children:"33.3 SAML Application Integration (Demonstrated)"}),"\n",(0,a.jsx)(t.p,{children:"The integration pattern, shown against an RSA-internal test SP supporting IdP-initiated flow: download the application's SAML metadata; in the central authentication section of am8config.xml, configure the application entry \u2014 ACS URL, issuer/entity ID, keystore reference \u2014 save, restart, and the application appears on the user's portal. The trainer then attempted the inverse pattern \u2014 PCAP as IdP with the Prime SSP itself as the SP \u2014 so SSP's login page offers a SAML method that redirects to PCAP for authentication and returns the user to SSP on success."}),"\n",(0,a.jsx)(t.h2,{id:"334-the-extended-live-debug--and-what-it-taught",children:"33.4 The Extended Live Debug \u2014 and What It Taught"}),"\n",(0,a.jsx)(t.p,{children:"The PCAP demos fought back for a substantial stretch, and the debugging arc was itself a masterclass in the layered failure modes of SAML configuration:"}),"\n",(0,a.jsxs)(t.ol,{children:["\n",(0,a.jsx)(t.li,{children:"Certificate path illusion. Config files edited in Windows Notepad while the application runs in a Linux container \u2014 the certificate path that looked right in the editor didn't exist at the Linux runtime path. Fixed by correcting the path; the 'cannot find certificate' error vanished."}),"\n",(0,a.jsx)(t.li,{children:"Missing SAML keystore. The referenced IdP keystore lacked the needed entry; a SAML signing keystore was generated on the spot ('pretty standard SAML configuration \u2014 nothing product-specific') and wired in."}),"\n",(0,a.jsxs)(t.li,{children:["Issuer-ID collision hypothesis. With the app still failing, suspected duplicate issuer IDs/application names were tested (renaming with a suffix), and the working HTAP/SSP entries were used as reference templates \u2014 an underrated technique: ",(0,a.jsx)(t.em,{children:"when a new integration fails, clone a known-good one and change one thing at a time"}),"."]}),"\n",(0,a.jsx)(t.li,{children:"WAR version mismatch \u2014 the actual fix. The root cause was the version of the AM8/PCAP WAR files in the Docker environment; patching to the latest WARs (Section 33.5) resolved it, and when Docker still misbehaved, the trainer fell back to his slower Linux VM where the identical configuration worked end-to-end \u2014 both the IdP-initiated portal launch and the SP-initiated SSP\u2192PCAP\u2192SSP round trip. Where logs fell short during this debug, the trainer opened a Jira on the spot to get the missing diagnostic information added to the product \u2014 a live example of how field friction becomes product improvement."}),"\n"]}),"\n",(0,a.jsx)(t.h2,{id:"335-patching-and-rollback-via-war-files-bonus-module",children:"33.5 Patching and Rollback via WAR Files (Bonus Module)"}),"\n",(0,a.jsx)(t.p,{children:"The mid-debug patch became its own lesson, delivered directly to Jacob for onsite use. Prime fixes are distributed as WAR files via Sean's OneDrive. The workflow: download the WARs \u2192 drop them into the patches folder wherever the kit runs \u2192 restart the service. The restart auto-ingests the patches (the files visibly disappear from the folder as they're copied in) and replaces the running WARs. Rollback is symmetrical: the pre-patch files are automatically preserved in the backups folder; to revert, copy the backup into patches, strip the suffix so the file ends in .war, restart \u2014 'back in business.' This is the same mechanism behind the day-or-two patch turnaround praised in Day 1's field discussion."}),"\n",(0,a.jsx)(t.h2,{id:"336-compliance-sidebar-soc-reports",children:"33.6 Compliance Sidebar: SOC Reports"}),"\n",(0,a.jsx)(t.p,{children:"A customer-assurance question surfaced a useful fact: RSA holds SOC 2 and SOC 3 reports, available through engineering on request \u2014 SOC 3 is publicly shareable, while SOC 2 typically requires the customer to sign an NDA. This complements the STIG evidence thread from Day 1 Section 14 in the audit-readiness toolkit."})]})}function c(e={}){const{wrapper:t}={...(0,s.R)(),...e.components};return t?(0,a.jsx)(t,{...e,children:(0,a.jsx)(h,{...e})}):h(e)}},8453:(e,t,i)=>{i.d(t,{R:()=>o,x:()=>r});var n=i(6540);const a={},s=n.createContext(a);function o(e){const t=n.useContext(s);return n.useMemo(function(){return"function"==typeof e?e(t):{...t,...e}},[t,e])}function r(e){let t;return t=e.disableParentContext?"function"==typeof e.components?e.components(a):e.components||a:o(e.components),n.createElement(s.Provider,{value:t},e.children)}}}]);